SELECT arm_name
FROM robotic_arms
WHERE arm_type = 'robotic gripper';

SELECT arm_type, COUNT(*) AS arm_count
FROM robotic_arms
GROUP BY arm_type;

SELECT COUNT(arm_id) AS arm_count
FROM robotic_arms
WHERE arm_type = 'robotic gripper';

SELECT data_id, arm_id, collection_date
FROM sensor_data
ORDER BY collection_date DESC;

SELECT arm_name, arm_type
FROM robotic_arms
ORDER BY arm_name;
